@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_e04e89eef40b46a3b04480ff51e8c4a8.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">
            Refreshing&hellip;
        </div>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();

            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload if the cuisine actually changed.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for a previous cuisine.
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);

        _error = null;
        _isRefreshing = _recipes is not null;

        var cancellationToken = _loadCts.Token;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Cancelled because user navigated to a different cuisine or left the page. Do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

